#!/usr/bin/env bash
# PreToolUse hook: protect sensitive and auto-generated files from Write/Edit.
# Reads Claude Code hook JSON from stdin. Outputs block decision or exits 0 (allow).
set -euo pipefail

# Fail-open if jq is missing
if ! command -v jq &>/dev/null; then
  exit 0
fi

FILE_PATH=$(jq -r '.tool_input.file_path // empty' 2>/dev/null)
[ -z "$FILE_PATH" ] && exit 0

# Resolve to basename and relative path for pattern matching
BASENAME=$(basename "$FILE_PATH")
# Get workspace root (two levels up from this script)
ROOT="$(cd "$(dirname "$0")/../.." && pwd)"
REL_PATH="${FILE_PATH#"$ROOT"/}"

block() {
  local reason="$1"
  cat <<JSON
{"decision":"block","reason":"$reason"}
JSON
  exit 0
}

# ── Environment files (secrets) ──────────────────────────────────────────────
case "$BASENAME" in
  .env|.env.*)
    block "Protected file: $BASENAME. Environment files may contain secrets."
    ;;
esac

# ── Git internals ────────────────────────────────────────────────────────────
if echo "$REL_PATH" | grep -qE '^\.git/|/\.git/'; then
  block "Protected path: .git/ internals must not be modified by agents."
fi

# ── Auto-generated workspace files ───────────────────────────────────────────
case "$REL_PATH" in
  WORKSPACE.md|mAIcelium.code-workspace)
    block "Protected file: $REL_PATH is auto-generated. Use bin/ scripts to modify it."
    ;;
  .claude/projects-context.md)
    block "Protected file: projects-context.md is auto-generated by sync_symlinks.sh."
    ;;
esac

# ── Agent config (prevent self-modification of permissions) ──────────────────
case "$REL_PATH" in
  .claude/settings.json|.claude/settings.local.json)
    block "Protected file: $REL_PATH. Agent must not modify its own permissions."
    ;;
esac

# ── Auto-generated IDE dotfolders ────────────────────────────────────────────
if echo "$REL_PATH" | grep -qE '^\.(cursor|agents|antigravity)/'; then
  block "Protected path: $REL_PATH is auto-generated via symlinks. Write to mesh/ instead."
fi

# ── Lockfiles ────────────────────────────────────────────────────────────────
case "$BASENAME" in
  package-lock.json|yarn.lock|pnpm-lock.yaml|poetry.lock|Pipfile.lock)
    block "Protected file: $BASENAME is a lockfile. Use the package manager to update it."
    ;;
esac

# All checks passed — allow silently
exit 0
